// Simple passthrough - extract data from webhook
const webhookData = $('Webhook').first().json;

return {
  json: {
    user_id: webhookData.user_id,
    session_id: webhookData.session_id,
    agent_name: webhookData.agent_name || 'brandy',
    timestamp_of_call_made: webhookData.timestamp_of_call_made || new Date().toISOString(),
    request_id: webhookData.request_id,
    user_mssg: webhookData.user_mssg || webhookData.message || '',
    conversation_state: webhookData.conversation_state || null
  }
};

// Format response to match frontend expectations
const webhookData = $('Extract Data').first().json;
const aiData = $('AI Agent - Brandy').first().json;

// Extract AI response
let aiResponse = "I'm here to help with your brand!";
let status = "Ready";
let phase = "assessment";
let wizard_step = 0;

if (aiData.output) {
  if (typeof aiData.output === 'string') {
    try {
      const parsed = JSON.parse(aiData.output);
      aiResponse = parsed.response || aiData.output;
      status = parsed.status || parsed.Status || "Ready";
      phase = parsed.phase || "assessment";
      wizard_step = parsed.wizard_step || 0;
    } catch (e) {
      aiResponse = aiData.output;
    }
  } else if (typeof aiData.output === 'object') {
    aiResponse = aiData.output.response || JSON.stringify(aiData.output);
    status = aiData.output.status || aiData.output.Status || "Ready";
    phase = aiData.output.phase || "assessment";
    wizard_step = aiData.output.wizard_step || 0;
  }
}

// Build proper response structure
const response = {
  user_id: webhookData.user_id,
  session_id: webhookData.session_id,
  agent_name: "brandy",
  timestamp_of_call_made: webhookData.timestamp_of_call_made,
  request_id: webhookData.request_id,
  agent_response: aiResponse,
  agent_status: status,
  state: {
    phase: phase,
    brand_exists: false,
    wizard_step: wizard_step,
    wizard_data: {},
    import_status: null
  }
};

return { json: response };
